export const PCTL_BANDS = [3, 10, 25, 50, 75, 90, 97];
// z-scores for the standard percentile bands (exact normal quantiles).
const BAND_Z = { 3: -1.880794, 10: -1.281552, 25: -0.674490, 50: 0, 75: 0.674490, 90: 1.281552, 97: 1.880794 };

// Abramowitz-Stegun 7.1.26 erf approximation (|err| < 1.5e-7).
function erf(x) {
  const s = x < 0 ? -1 : 1; x = Math.abs(x);
  const t = 1 / (1 + 0.3275911 * x);
  const y = 1 - (((((1.061405429 * t - 1.453152027) * t) + 1.421413741) * t - 0.284496736) * t + 0.254829592) * t * Math.exp(-x * x);
  return s * y;
}
export function zToPctl(z) { return 50 * (1 + erf(z / Math.SQRT2)); }

function lmsAt(metric, sex, age) {
  const tbl = CDC_LMS[metric] && CDC_LMS[metric][String(sex)];
  if (!tbl) return null;
  const ages = Object.keys(tbl).map(Number).sort((a, b) => a - b);
  if (!ages.length) return null;
  if (age <= ages[0]) return tbl[ages[0]];
  if (age >= ages[ages.length - 1]) return tbl[ages[ages.length - 1]];
  let lo = ages[0];
  for (const a of ages) { if (a <= age) lo = a; }
  const hi = ages.find((a) => a > lo);
  const t = (age - lo) / (hi - lo), A = tbl[lo], B = tbl[hi];
  return [A[0] + (B[0] - A[0]) * t, A[1] + (B[1] - A[1]) * t, A[2] + (B[2] - A[2]) * t];
}

// Percentile (0–100) for a measured value. metric: 'stature'|'weight'|'bmi'.
export function percentileFor(metric, sex, ageYears, value) {
  const lms = lmsAt(metric, sex, ageYears);
  if (!lms || !value) return null;
  const [L, M, S] = lms;
  const z = L !== 0 ? (Math.pow(value / M, L) - 1) / (L * S) : Math.log(value / M) / S;
  return { z, pctl: zToPctl(z) };
}

// Value at a given band percentile (for drawing the curves).
export function valueAtBand(metric, sex, ageYears, band) {
  const lms = lmsAt(metric, sex, ageYears);
  if (!lms) return null;
  const [L, M, S] = lms, z = BAND_Z[band];
  return L !== 0 ? M * Math.pow(1 + L * S * z, 1 / L) : M * Math.exp(S * z);
}

